import React, { useState } from "react";
import "./GhiDanhNhapHoc.css";
import { useCMS } from "../../contexts/CMSContext";

const GhiDanhNhapHoc: React.FC = () => {
  const { cmsData } = useCMS();
  const c = cmsData.pages.page2.ghiDanhNhapHocContent;

  const [birthDate, setBirthDate] = useState("");
  const [dateError, setDateError] = useState("");

  if (!c) return null;

  const validateDate = (value: string) => {
    const r = /^(\d{1,2})\/(\d{1,2})\/(\d{4})$/;
    if (!r.test(value)) {
      setDateError("Định dạng không hợp lệ (dd/mm/yyyy)");
      return;
    }

    const [, d, m, y] = value.match(r)!;
    const date = new Date(+y, +m - 1, +d);
    if (
      date.getDate() !== +d ||
      date.getMonth() !== +m - 1 ||
      date.getFullYear() !== +y
    ) {
      setDateError("Ngày không hợp lệ");
      return;
    }

    setDateError("");
  };

  return (
    <section id="GHI-DANH-NHẬP-HỌC">
      <section className="register-section register-desktop">
        <div className="register-container">

          <div className="register-image">
            <img src={c.desktopImage} alt="Bồ đề" />
          </div>

          <div className="register-form">
            <h2 className="register-title">{c.title}</h2>
            <div className="register-underline" />

            <form>
              <div className="form-grid">

                <div className="form-group">
                  <label>{c.fields.fullName.label}</label>
                  <input placeholder={c.fields.fullName.placeholder} />
                </div>

                <div className="form-group">
                  <label>{c.fields.dharmaName.label}</label>
                  <input placeholder={c.fields.dharmaName.placeholder} />
                </div>

                <div className="form-group">
                  <label>{c.fields.birthDate.label}</label>
                  <input
                    placeholder={c.fields.birthDate.placeholder}
                    value={birthDate}
                    onChange={e => {
                      setBirthDate(e.target.value);
                      validateDate(e.target.value);
                    }}
                    className={dateError ? "error" : ""}
                  />
                  {dateError && (
                    <span className="error-message">{dateError}</span>
                  )}
                </div>

                <div className="form-group">
                  <label>{c.fields.gender.label}</label>
                  <div className="radio-group">
                    <label>
                      <input type="radio" name="gender" />
                      {c.fields.gender.male}
                    </label>
                    <label>
                      <input type="radio" name="gender" />
                      {c.fields.gender.female}
                    </label>
                  </div>
                </div>

                <div className="form-group">
                  <label>{c.fields.email.label}</label>
                  <input placeholder={c.fields.email.placeholder} />
                </div>

                <div className="form-group">
                  <label>{c.fields.phone.label}</label>
                  <input placeholder={c.fields.phone.placeholder} />
                </div>

                <div className="form-group">
                  <label>{c.fields.program.label}</label>
                  <select>
                    {c.fields.program.options.map(o => (
                      <option key={o.id}>{o.label}</option>
                    ))}
                  </select>
                </div>

                <div className="form-group">
                  <label>{c.fields.attendance.label}</label>
                  <select>
                    {c.fields.attendance.options.map(o => (
                      <option key={o.id}>{o.label}</option>
                    ))}
                  </select>
                </div>

              </div>

              <div className="form-submit">
                <button type="submit">{c.submitLabel}</button>
              </div>
            </form>
          </div>
        </div>
      </section>
    </section>
  );
};

export default GhiDanhNhapHoc;
